mapper.select:
SELECT u.user_id AS userId, u.user_name AS userName, u.real_name AS realName, u.user_type AS userType, u.student_no AS studentNo, u.teacher_no AS teacherNo, u.college_id AS collegeId, u.major_id AS majorId, u.campus_id AS campusId, c.campus_name AS campusName, u.user_avatar AS userAvatar, u.user_phone AS userPhone, u.user_email AS userEmail, u.status, u.create_time AS createTime, u.update_time AS updateTime, GROUP_CONCAT(r.role_name ORDER BY r.role_id) AS roleNames FROM sys_user u LEFT JOIN sys_user_role ur ON u.user_id = ur.user_id LEFT JOIN sys_role r ON ur.role_id = r.role_id LEFT JOIN sys_campus c ON u.campus_id = c.campus_id WHERE u.is_deleted = 0
AND (u.user_name LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%'))
AND c.campus_name LIKE CONCAT('%', #{campusName}, '%')
AND u.user_type = #{userType}
AND u.status = #{status}
GROUP BY u.user_id ORDER BY u.user_id ASC LIMIT #{offset}, #{limit}

SELECT COUNT(DISTINCT u.user_id) FROM sys_user u LEFT JOIN sys_campus c ON u.campus_id = c.campus_id WHERE u.is_deleted = 0
AND (u.user_name LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%'))
AND c.campus_name LIKE CONCAT('%', #{campusName}, '%')
AND u.user_type = #{userType}
AND u.status = #{status}
